('engels', 'klas3', NULL, 'What does ''hermeneutics'' mean?', '["Stijlanalyse, Schrijfstijl en Narratologie van tekstinterpretatie","Schrijfstijl","De theorie en methodologie van tekstinterpretatie","Narratologie"]'::jsonb, 2, 'Hermeneutics: the theory of how we interpret texts and find meaning.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('engels', 'klas3', NULL, 'What is ''sibilance'' as a sound device?', '["Herhaling van ''s'' en ''sh'' klanken","Herhaling van medeklinkers","Assonantie","Herhaling van medeklinkers of Assonantie"]'::jsonb, 0, 'Sibilance: ''the soft sound of serpents slithering'' — repeated s/sh sounds for effect.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('engels', 'klas3', NULL, 'What does ''palimpsest'' mean as a literary concept?', '["Een modern boek","Een manuscripttype die eerdere teksten bevat of verwijzingen daarnaar","Een manuscripttype","Een tekst die eerdere teksten bevat of verwijzingen daarnaar"]'::jsonb, 3, 'Palimpsest: a text layered over older texts, revealing traces of earlier writing/meaning.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('engels', 'klas3', NULL, 'What is ''defamiliarization'' (Shklovsky)?', '["Symbolisme","Naturalisme","Symbolisme, Naturalisme en Realisme van het alledaagse zodat lezers het opnieuw beleven","Het vreemd maken van het alledaagse zodat lezers het opnieuw beleven"]'::jsonb, 3, 'Ostranenie: art should make the familiar strange to renew our perception.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('engels', 'klas3', NULL, 'What is ''register'' in language?', '["Woordenschat","Taalstijl op zichzelf","Het taalniveau aangepast aan context, relatie en doel (formeel/informeel)","Woordenschat, Taalstijl op zichzelf en Uitspraak aan context, relatie en doel (formeel/informeel)"]'::jsonb, 2, 'Register: formal, informal, academic, conversational — adjusted to situation and audience.', NULL, 'sample', NULL, NULL, FALSE, NULL),
