('economie', 'klas3', NULL, 'Wat is monetaire transmissie?', '["De overdracht van inflatie van het ene land naar het andere of De financiering van staatsleningen via de obligatiemarkt","De overdracht van inflatie van het ene land naar het andere","De financiering van staatsleningen via de obligatiemarkt","Het mechanisme waarmee veranderingen in de geldmarkt doorwerken in de reele economie"]'::jsonb, 3, 'ECB verlaagt rente → banken lenen goedkoper → bedrijven investeren meer → vraag neemt toe → BBP stijgt. Dit transmissiekanaal werkt via krediet, vermogen, wisselkoers en verwachtingen.', NULL, 'sample', 'vraag-aanbod-economie', 4, FALSE, NULL),
('economie', 'klas3', NULL, 'Wat is prijselasticiteit van de vraag?', '["De procentuele verandering van gevraagde hoeveelheid gedeeld door procentuele prijsverandering","Het verschil tussen vraag en aanbod bij gegeven prijs of De minimumprijs waarbij vraag nul wordt","De minimumprijs waarbij vraag nul wordt","Het verschil tussen vraag en aanbod bij gegeven prijs"]'::jsonb, 0, 'Ed = %ΔQ/%ΔP. Inelastisch: |Ed| < 1 (bv. medicijnen). Elastisch: |Ed| > 1 (bv. luxegoederen). Bepaalt effect van belasting op consument vs. producent.', NULL, 'sample', 'vraag-aanbod-economie', 1, FALSE, NULL),
('economie', 'klas3', NULL, 'Wat is het Nash-evenwicht?', '["Een situatie waarbij alle speler zijn resultaat kan verbeteren door eenzijdig van strategie te veranderen","De strategie waarbij de totale opbrengst gemaximaliseerd wordt","Een situatie waarbij geen speler zijn resultaat kan verbeteren door eenzijdig van strategie te veranderen","De optimale strategie voor beide spelers bij samenwerking"]'::jsonb, 2, 'Nash-evenwicht: elke speler speelt zijn beste reactie op wat de andere doet. Niet noodzakelijk Pareto-optimaal (bv. gevangenendilemma: beide defecteren = Nash, maar beide coopereren geeft hogere opbrengst).', NULL, 'sample', 'vraag-aanbod-economie', 6, FALSE, NULL),
('economie', 'klas3', NULL, 'Wat is Keynesiaans beleid?', '["Overheidsbeleid dat vraagstimulering via uitgaven en belastingverlaging gebruikt om recessies te bestrijden","Overheidsbeleid gericht op deregulering en privatisering","Monetair beleid van centrale banken om inflatie te beheersen","Monetair beleid van centrale banken om inflatie te beheersen of Overheidsbeleid gericht op deregulering en privatisering"]'::jsonb, 0, 'Keynes (1936): bij onderbesteding kan de overheid de vraag stimuleren (bestedingsimpuls). Overcapaciteit? Overheid investeert, multipliereffect vergroot nationaal inkomen.', NULL, 'sample', 'vraag-aanbod-economie', 4, FALSE, NULL),
('economie', 'klas3', NULL, 'Wat is supply-side economie?', '["Beleid gericht op vraagstimulering via overheidsuitgaven of De studie van prijsvorming op aanbodzijde van de markt","De studie van prijsvorming op aanbodzijde van de markt","Beleid gericht op vraagstimulering via overheidsuitgaven","Beleid dat productiecapaciteit vergroot door belastingverlaging, deregulering en arbeidsmarktflexibilisering"]'::jsonb, 3, 'Supply-side: verbeter aanbodcapaciteit (lagere belasting op arbeid/kapitaal, minder regulering) om economische groei te stimuleren. Reagan, Thatcher als bekende voorstanders.', NULL, 'sample', 'vraag-aanbod-economie', 0, FALSE, NULL),
('economie', 'klas3', NULL, 'Wat is overheidsfalen?', '["Het onvermogen van de overheid om belasting te innen","Het onvermogen van de overheid om belasting te innen of Een begroting die structureel in tekort is","De situatie waarbij overheidsinterventie leidt tot minder efficiente uitkomsten dan de markt","Een begroting die structureel in tekort is"]'::jsonb, 2, 'Overheidsfalen: overheidsinterventie kan inefficient zijn door onvolledige informatie, politieke beweegredenen, hoge administratiekosten of onbedoelde bijeffecten. Complement aan marktfalen.', NULL, 'sample', 'vraag-aanbod-economie', 5, FALSE, NULL),
('economie', 'klas3', NULL, 'Wat is de wisselkoers en hoe beinvloedt deprecie de export?', '["Wisselkoers bepaalt de inflatie; apprecie verhoogt de export","Wisselkoers is de goudreserve per eenheid geld; onafhankelijk van export","Wisselkoers is de prijs van een valuta in een andere valuta; deprecie maakt export goedkoper voor buitenlanders","Wisselkoers is de prijs van een valuta in een andere valuta; deprecie maakt export goedkoper achter buitenlanders"]'::jsonb, 2, 'Deprecie van euro: buitenlanders kopen meer euros met hun valuta → Europese export wordt relatief goedkoper → exportvraag stijgt. J-curve: korte termijn verslechtert eerst, daarna verbetering.', NULL, 'sample', 'vraag-aanbod-economie', 4, FALSE, NULL)
INSERT INTO public.questions (subject, level, topic_key, q, options, answer, explanation, svg, source, path_id, step_idx, image_in_explanation, question_source) VALUES
('economie', 'klas3', NULL, 'Wat is het verschil tussen nominaal en reeel BBP?', '["Er is geen praktisch verschil voor beleidsbeslissingen","Nominaal BBP meet in lopende prijzen; reeel BBP corrigeert achter prijsstijgingen door constante basisprijzen te gebruiken","Reeel BBP telt alleen goederen mee; nominaal ook diensten","Nominaal BBP meet in lopende prijzen; reeel BBP corrigeert voor prijsstijgingen door constante basisprijzen te gebruiken"]'::jsonb, 3, 'Nominaal BBP gebruikt huidige prijzen (beïnvloed door inflatie). Reeel BBP gebruikt basisjaar-prijzen → meet echte groei van productie. BBP-deflator = (nominaal/reeel) × 100.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('economie', 'klas3', NULL, 'Wat is marktmacht bij een monopolie?', '["Het vermogen om marktprijzen te beïnvloeden door aanpassing van de output","Het vermogen om buitenlandse concurrentie te weren met invoerrechten","De hoeveelheid aandelen in handen van het bedrijf","De mate van technologische voorsprong op concurrenten"]'::jsonb, 2, 'Een monopolist is een prijszetter: door output te beperken stijgt de prijs (P > MC). Welvaartverlies (deadweight loss): consumenten betalen meer, minder wordt geproduceerd dan sociaal optimum.', NULL, 'sample', 'vraag-aanbod-economie', 1, FALSE, NULL),
('economie', 'klas3', NULL, 'Wat is het begrotingsbeleid (fiscaal beleid)?', '["Mededingingsbeleid via anti-kartelmaatregelen of Monetair beleid van de centrale bank","Mededingingsbeleid via anti-kartelmaatregelen","Monetair beleid van de centrale bank","Overheidsbeleid via belastingen en uitgaven om de economie te sturen"]'::jsonb, 3, 'Fiscaal beleid: overheid gebruikt belastingen (verlagen = vraagstimulus) en uitgaven (verhogen = bestedingsimpuls) om conjunctuur te beinvloeden. Anticyclisch = expansief bij recessie, restrictief bij hoogconjunctuur.', NULL, 'sample', 'vraag-aanbod-economie', 3, FALSE, NULL),
('economie', 'klas3', NULL, 'Wat is de betalingsbalans van een land?', '["Het overzicht van alle economische transacties tussen een land en de rest van de wereld","De verhouding tussen import en export van goederen","Het overzicht van geen economische transacties tussen een land en de rest van de wereld","De verhouding tussen staatsschuld en BBP"]'::jsonb, 0, 'Betalingsbalans: lopende rekening (handel, inkomens), kapitaalrekening (investeringen) en financiele rekening. Tekort op lopende rekening betekent dat een land meer importeert dan exporteert.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('economie', 'klas3', NULL, 'Wat is asymmetrische informatie?', '["Wanneer een partij bij een transactie meer informatie heeft dan de andere partij","Wanneer bedrijven onvolledige informatie hebben over productiekosten","Wanneer een partij bij een transactie minder informatie heeft dan de andere partij","Wanneer prijsinformatie niet beschikbaar is voor consumenten"]'::jsonb, 0, 'Asymmetrische informatie leidt tot marktfalen: adverse selectie (bv. tweedehands auto markt: verkoper weet meer dan koper → lemons problem, Akerlof) en moral hazard (verzekeraar weet minder dan verzekerde).', NULL, 'sample', 'vraag-aanbod-economie', 2, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een persoonsvorm?', '["Het werkwoord dat de persoon en tijd aangeeft in een zin","Een zelfstandig naamwoord","Een bijvoeglijk naamwoord","Een zelfstandig naamwoord dat de persoon en tijd aangeeft in een zin"]'::jsonb, 0, 'De persoonsvorm is het vervoegde werkwoord: ''Hij loopt'' → ''loopt'' is de pv.', NULL, 'sample', 'werkwoordsvervoeging', 2, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een hoofdzin?', '["Een tussenwerper","Een zin die niet zelfstandig kan staan of Een tussenwerper","Een zin die zelfstandig een complete gedachte uitdrukt","Een zin die niet zelfstandig kan staan"]'::jsonb, 2, 'Een hoofdzin is zelfstandig en bevat minstens een onderwerp en persoonsvorm.', NULL, 'sample', 'zinsontleding', 1, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een metafoor?', '["Een beeldspraak waarbij iets vergeleken wordt zonder vergelijkingswoord","Een overdrijving","Een overdrijving, Een herhaling en Een vergelijking met ''zoals'' of ''als'' wordt zonder vergelijkingswoord","Een vergelijking met ''zoals'' of ''als''"]'::jsonb, 0, 'Metafoor: ''Het leven is een reis'' — geen ''zoals'', direct gelijkstelling.', NULL, 'sample', 'vergelijkingen-oplossen', 0, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is de verleden tijd van ''rijden''?', '["Gerijden","Gereden","Gerijden of Gereden","Reed / reden"]'::jsonb, 3, 'Rijden is een sterk werkwoord: onvoltooid verleden tijd = reed (enkelvoud) / reden (meervoud).', NULL, 'sample', 'werkwoordsvervoeging', 6, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een bijvoeglijk naamwoord?', '["Een voornaamwoord dat een eigenschap van een zelfstandig naamwoord beschrijft","Een werkwoord","Een woord dat een eigenschap van een zelfstandig naamwoord beschrijft","Een voornaamwoord"]'::jsonb, 2, 'BV: ''de grote hond'' — ''grote'' is het bijvoeglijk naamwoord.', NULL, 'sample', 'zinsontleding', 10, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een synoniem?', '["Een woord met (bijna) dezelfde betekenis","Een woord met tegengestelde betekenis","Een samengesteld woord","Een woord met tegengestelde betekenis of Een samengesteld woord"]'::jsonb, 0, 'Synoniemen: blij = vrolijk = opgewekt. Ze zijn uitwisselbaar in context.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Welk leesteken geeft een vraag aan?', '["?",".",";","!"]'::jsonb, 0, 'Een zin die een vraag stelt, eindigt met een vraagteken (?).', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is de verkleinvorm van ''tafel''?', '["Tafelen","Tafeldje","Tafeltje","Tafeltjen"]'::jsonb, 2, 'Verkleinvorm van ''tafel'' = ''tafeltje'' (met verkleiningsuitgang -tje).', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een actieve zin?', '["De handelende persoon is het lijdend voorwerp","Er is geen werkwoord","De handeling is in de verleden tijd","Het onderwerp voert de handeling uit"]'::jsonb, 3, 'Actief: ''De hond bijt de man.'' — de hond (onderwerp) bijt (handeling).', NULL, 'sample', 'zinsontleding', 6, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een passieve zin?', '["Het onderwerp ondergaat de handeling (er staat ''worden'' of ''zijn'' + voltooid deelwoord)","Het onderwerp ondergaat de handeling (er staat ''worden'' of ''zijn'' + onvoltooid deelwoord)","Een ontkenningszin","De handelende persoon is het onderwerp"]'::jsonb, 0, 'Passief: ''De man wordt gebeten (door de hond).'' — man ondergaat de handeling.', NULL, 'sample', 'werkwoordsvervoeging', 0, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een enkelvoudig onderwerp?', '["Eén persoon of ding als onderwerp in de zin","Meerdere personen als onderwerp of Een bijzin als onderwerp","Een bijzin als onderwerp","Meerdere personen als onderwerp"]'::jsonb, 0, 'Enkelvoudig onderwerp: ''De leerling leest.'' — ''De leerling'' is het onderwerp.', NULL, 'sample', 'zinsontleding', 2, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een direct object (lijdend voorwerp)?', '["Het bijvoeglijk naamwoord dat de handeling rechtstreeks ondergaat","Het meewerkend voorwerp","Het zelfstandig naamwoord dat de handeling rechtstreeks ondergaat","De handelende persoon"]'::jsonb, 2, 'LV: ''Zij leest een boek.'' — ''een boek'' is het lijdend voorwerp (wat wordt gelezen?).', NULL, 'sample', 'werkwoordsvervoeging', 0, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een samengesteld woord?', '["Een woord opgebouwd uit twee of minder zelfstandige woorden","Een leenwoord","Een woord met een voor- of achtervoegsel","Een woord opgebouwd uit twee of meer zelfstandige woorden"]'::jsonb, 3, 'Samengestelde woorden: ''voetbal'', ''boekenkast'', ''zonnebril''.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Welke schrijfwijze is correct?', '["Hij heeft een grotes fout gemaakt","Hij heeft een groote fout gemaakt","Hij heeft een groot fout gemaakt","Hij heeft een grote fout gemaakt"]'::jsonb, 3, 'Na ''een'' + zelfstandig naamwoord: bijvoeglijk naamwoord krijgt -e: ''grote fout''.', NULL, 'sample', 'werkwoordsvervoeging', 8, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een tussenwerper (interjectie)?', '["Een bijwoord, Een werkwoord en Een voegwoord dat een gevoel uitdrukt (bijv. ''Au!'', ''Hé!'', ''Pfff'')","Een werkwoord","Een uitroepwoord dat een gevoel uitdrukt (bijv. ''Au!'', ''Hé!'', ''Pfff'')","Een voegwoord"]'::jsonb, 2, 'Tussenwerpers staan los van de zinsgrammatica en drukken emotie uit.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is de stam van het werkwoord ''werken''?', '["Werk","Werkende","Werken","Gewerkt"]'::jsonb, 0, 'Stam = infinitief minus -en: werk-en → ''werk''.', NULL, 'sample', 'werkwoordsvervoeging', 5, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een ontkennende zin?', '["Een zin met ''niet'' of ''geen'' die iets ontkent","Een uitroepzin","Een zin met ''niet'' of ''alle'' die iets ontkent","Een vraagzin"]'::jsonb, 0, 'Ontkenning met ''niet'': ''Ik ga niet mee.'' Of ''geen'': ''Ik heb geen tijd.''', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is alliteratie?', '["Rijm aan het einde van regels van dezelfde beginletter/klanken in opeenvolgende woorden","Rijm in het midden","Herhaling van dezelfde beginletter/klanken in opeenvolgende woorden","Rijm aan het einde van regels"]'::jsonb, 2, 'Alliteratie: ''De dikke dame danst door de dag.'' — beginletter D herhaalt zich.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is het verschil tussen ''hun'' en ''hen''?', '["''Hun'' is meewerkend voorwerp; ''hen'' is lijdend voorwerp of na voorzetsel","''hen'' is lijdend voorwerp of na voorzetsel; ''Hun'' is meewerkend voorwerp","''Hun'' staat nooit bij een werkwoord","''Hen'' is altijd fout"]'::jsonb, 0, 'Hun geven (mv): ''Ik geef HUN een cadeau.'' Hen zien: ''Ik zie HEN.'' Na voorzetsel: ''Met HEN.''', NULL, 'sample', 'woordsoorten-nederlands', 7, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een woordveld?', '["Synoniemen alleen","Een woordsoortindeling","Alle vervoegingen van een werkwoord onder bepaalde omstandigheden","Een groep woorden die inhoudelijk bij hetzelfde onderwerp horen"]'::jsonb, 3, 'Woordveld ''school'': leerling, leraar, les, klas, rapport, schoolbord.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een voornaamwoord?', '["Een naam van een persoon","Een bijvoeglijk naamwoord dat een zelfstandig naamwoord vervangt (ik, hij, dit, die)","Een bijvoeglijk naamwoord","Een woord dat een zelfstandig naamwoord vervangt (ik, hij, dit, die)"]'::jsonb, 3, 'Voornaamwoorden: persoonlijk (ik, jij), bezittelijk (mijn, jouw), aanwijzend (deze, die).', NULL, 'sample', 'woordsoorten-nederlands', 6, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een bijzin?', '["Een zelfstandige zin","Een zelfstandige zin die afhankelijk is van een andere zin en begint met een voegwoord","Een vraagzin","Een zin die afhankelijk is van een andere zin en begint met een voegwoord"]'::jsonb, 3, 'Bv: ''Ik weet dat hij komt.'' — ''dat hij komt'' is een bijzin (begint met ''dat'').', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is de stijl van een tekst?', '["De manier waarop een schrijver taal gebruikt (woordkeuze, zinsbouw, toon)","De inhoud, Het genre en De opbouw waarop een schrijver taal gebruikt (woordkeuze, zinsbouw, toon)","Het genre","De opbouw"]'::jsonb, 0, 'Stijl omvat alle talige keuzes: formeel/informeel, beknopt/uitgebreid, literair/zakelijk.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een verkleinwoord (diminutief)?', '["Een meervoudsvorm","Een kleiner of vriendelijker variant van een bijvoeglijk naamwoord","Een kleiner of vriendelijker variant van een zelfstandig naamwoord","Een vergroting van een woord"]'::jsonb, 2, 'Verkleinwoorden: ''huisje'', ''katje'', ''boompje'' — kleiner of liefkozend.', NULL, 'sample', 'spelling', 10, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is het verschil tussen ''dan'' en ''als''?', '["''Dan'' = vergelijking na comparatief; ''als'' = gelijkheid of voorwaarde","Beide zijn voegwoorden bij vergelijkingen","''Als'' = vergelijking na comparatief","Beide zijn voegwoorden bij vergelijkingen of ''Als'' = vergelijking na comparatief"]'::jsonb, 0, '''Harder dan jij'' (comparatief); ''net zo hard als jij'' (gelijkheid); ''als het regent'' (voorwaarde).', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een abstracte zelfstandig naamwoord?', '["Een onzichtbare, niet-tastbare begrip (vreugde, vrijheid, liefde)","Een persoon","Een dier","Een tastbaar ding in het dagelijks taalgebruik en literatuur"]'::jsonb, 0, 'Abstracte znw: ''geluk'', ''hoop'', ''verdriet'' — je kunt ze niet aanraken.', NULL, 'sample', 'woordsoorten-nederlands', 1, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een tautologie?', '["Een metafoor","Een metafoor van hetzelfde in andere woorden (bv. ''een oud grijsaard'')","Herhaling van hetzelfde in andere woorden (bv. ''een oud grijsaard'')","Overdrijving"]'::jsonb, 2, 'Tautologie: ''grijs'' en ''oud'' zeggen hetzelfde — overbodige herhaling.', NULL, 'sample', 'literatuurgeschiedenis', 12, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een hoofdzin in een samengestelde zin?', '["Een nevengeschikte zin","Een vraagzin","De zin die zelfstandig kan staan en de bijzin bevat of eraan gekoppeld is","Een nevengeschikte zin die zelfstandig kan staan en de bijzin bevat of eraan gekoppeld is"]'::jsonb, 2, 'In ''Ik weet dat hij komt'' is ''Ik weet'' de hoofdzin; ''dat hij komt'' de bijzin.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een formeel register?', '["Omgangstaal","Jeugdtaal","Dialect","Taalgebruik in officiële of professionele context met correct taalgebruik"]'::jsonb, 3, 'Formeel register: zakenbrieven, rapporten, vergaderingen — geen afkortingen of slang.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is het verschil tussen een enkelvoudige en samengestelde zin?', '["Een enkelvoudige zin heeft geen werkwoord; een samengestelde wel","Een samengestelde zin bestaat altijd uit twee hoofdzinnen","Een enkelvoudige zin heeft één persoonsvorm; een samengestelde zin heeft twee of meer persoonsvormen","Een enkelvoudige zin heeft één persoonsvorm; een samengestelde zin heeft twee of minder persoonsvormen"]'::jsonb, 2, 'Enkelvoudige zin: 1 persoonsvorm (bv. ''De leraar schrijft''). Samengestelde zin: 2+ persoonsvormen (bv. ''Ik weet dat hij schrijft'').', NULL, 'sample', 'werkwoordsvervoeging', 4, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een metafoor?', '["Een vergelijking met het woord ''als'' of ''zoals'' of Een overdrijving voor effect","Een vergelijking met het woord ''als'' of ''zoals''","Een overdrijving voor effect","Een stijlfiguur waarbij iets anders wordt vergeleken zonder vergelijkingswoord"]'::jsonb, 3, 'Metafoor: directe vergelijking zonder ''als/zoals''. Bv. ''Het leven is een reis.'' Bij een vergelijking zou staan: ''Het leven is als een reis.''', NULL, 'sample', 'vergelijkingen-oplossen', 0, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is het doel van een inleiding in een betoog?', '["Aandacht trekken, onderwerp introduceren en de stelling/these presenteren","De conclusie samenvatten","Tegenargumenten weerleggen","Argumenten geven voor het standpunt in de moderne taal- en letterkunde"]'::jsonb, 0, 'Een inleiding: haak (aandacht), context (achtergrond) en these/stelling (standpunt). De these is de centrale bewering die in het betoog verdedigd wordt.', NULL, 'sample', 'werkwoordsvervoeging', 10, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat zijn de drie tekstsoorten?', '["Informatief, betogend, beschouwend","Feitelijk, mening, fictief","Beschrijvend, verhalend, betogend","Informatief, persuasief, narratief"]'::jsonb, 0, 'De drie hoofdsoorten: informatief (feiten overdragen), betogend (overtuigen, standpunt verdedigen) en beschouwend (beschouwen/analyseren vanuit meerdere perspectieven).', NULL, 'sample', 'argumentatieleer', 0, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een signaalwoord voor tegenstelling?', '["Bovendien, ook, daarnaast","Eerst, daarna, ten slotte","Bovendien, ook, daarnaast of Eerst, daarna, ten slotte","Echter, maar, toch, desondanks"]'::jsonb, 3, 'Tegenstellingssignaalwoorden: echter, maar, toch, desondanks, niettemin. Ze introduceren een informatie die ingaat tegen het eerder gestelde.', NULL, 'sample', 'schrijfvaardigheid', 9, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is actief en passief taalgebruik?', '["Actief: het onderwerp voert de handeling uit; passief: het onderwerp ondergaat de handeling","Actief: tegenwoordige tijd; passief: verleden tijd","passief: het onderwerp voert de handeling uit; passief: het onderwerp ondergaat de handeling","Actief: persoonlijk schrijven; passief: onpersoonlijk schrijven"]'::jsonb, 0, 'Actief: ''De docent corrigeert de toets.'' Passief: ''De toets wordt door de docent gecorrigeerd.'' Passieve zin benadrukt het object; actieve zin de handeling en het subject.', NULL, 'sample', 'werkwoordsvervoeging', 9, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is het verschil tussen denotatie en connotatie?', '["Denotatie is de letterlijke woordbetekenis; connotatie de bijbetekenis of gevoelswaarde","Er is geen betekenisverschil in gangbaar taalgebruik","Denotatie gaat over uitspraak; connotatie over spelling","Denotatie gaat over uitspraak; connotatie over spelling of Er is geen betekenisverschil in gangbaar taalgebruik"]'::jsonb, 0, 'Denotatie: letterlijke betekenis (roos = plant). Connotatie: bijbetekenis (roos = liefde, schoonheid). Belangrijk voor analyse van reclame, poëzie en persuasieve teksten.', NULL, 'sample', 'literatuurgeschiedenis', 5, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een participiumzin?', '["Een bijzondere bijzin waarbij een deelwoord als werkwoord fungeert","Een zin met een persoonsvorm in de voltooide tijd","Een zin met een persoonsvorm in de voltooide tijd of Een zin met een zelfstandig naamwoord als kern","Een zin met een zelfstandig naamwoord als kern"]'::jsonb, 0, 'Participiumzin: bijzin met deelwoord als kern, zonder persoonsvorm. Bv. ''Moe van het werk, viel hij in slaap.'' (participium: ''moe van het werk'').', NULL, 'sample', 'werkwoordsvervoeging', 0, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een parafrase?', '["Een samenvatting of herformulering van een tekstdeel in eigen woorden","Een stijlfiguur waarbij iets overdreven wordt of Een vraag die retorisch gesteld wordt","Een vraag die retorisch gesteld wordt","Een stijlfiguur waarbij iets overdreven wordt"]'::jsonb, 0, 'Parafraseren: de inhoud van een passage weergeven in eigen woorden. Belangrijk bij samenvatten en tekstanalyse: je toont begrip zonder letterlijk te kopiëren.', NULL, 'sample', 'tekstanalyse', 8, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is de functie van leestekens in een tekst?', '["Enkel fouten aangeven in het schrijfproces","Enkel fouten aangeven in het schrijfproces, De lengte van zinnen bepalen en Alleen aesthetisch voor vormgeving van de tekst door pauzes, intonatie en relaties aan te geven","Structuur aanbrengen en betekenis verduidelijken door pauzes, intonatie en relaties aan te geven","Alleen aesthetisch voor vormgeving van de tekst"]'::jsonb, 2, 'Leestekens (punt, komma, dubbele punt, gedachtestreepje, aanhalingstekens) geven ritme, verduidelijken relaties tussen zinsdelen en sturen de interpretatie van de lezer.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is de zinsontleding van ''De kat bijt de hond''?', '["Onderwerp: de kat, persoonsvorm: bijt, lijdend voorwerp: de hond","Persoonsvorm: de kat, lijdend voorwerp: bijt, onderwerp: de hond","Meewerkend voorwerp: kat, gezegde: bijt, onderwerp: hond","Onderwerp: kat, gezegde: bijt de hond, lijdend voorwerp: hond"]'::jsonb, 0, 'Zinsontleding: onderwerp = ''de kat'' (wie bijt?), persoonsvorm = ''bijt'' (werkwoord), lijdend voorwerp = ''de hond'' (wat/wie wordt gebeten?).', NULL, 'sample', 'werkwoordsvervoeging', 2, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een anakoloet?', '["Een zinsconstructie die halverwege afgebroken en anders voortgezet wordt","Een chiastische woordvolgorde","Een herhaling van woorden aan het begin van zinnen of Een chiastische woordvolgorde","Een herhaling van woorden aan het begin van zinnen"]'::jsonb, 0, 'Anakoloet: zin begint met een bepaalde grammaticale constructie maar vervolgt anders. Bv. ''Die man die gisteren belde — ik wist niet wat ik moest zeggen.'' Geeft gesproken, onstuimig karakter.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Welke interpunctie gebruik je voor een opsomming bij een aankondiging?', '["Vraagteken","Dubbele punt gevolgd door de opsomming","Puntkomma","Gedachtestreepje onder bepaalde omstandigheden"]'::jsonb, 1, 'Na een aankondiging gebruik je een dubbele punt: ''Ik heb nodig: boeken, pen en papier.'' De dubbele punt kondigt de opsomming aan.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is de functie van de conclusie in een betoog?', '["Het standpunt en de argumenten samenvatten en de these bevestigen","De inleiding herhalen met andere woorden of Vragen stellen voor vervolgonderzoek","Vragen stellen voor vervolgonderzoek","De inleiding herhalen met andere woorden"]'::jsonb, 0, 'Conclusie: vat de argumenten samen, bevestigt de these en geeft eventueel een aanbeveling of call to action. Moet logisch volgen uit de argumentatie.', NULL, 'sample', 'argumentatieleer', 5, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een enjambement in poëzie?', '["Het doorlopen van een zin over de regelgrens heen zonder interpunctie","Een strofevorm met vier regels","Een rijmschema waarbij elke regel rijmt of Een strofevorm met vier regels","Een rijmschema waarbij elke regel rijmt"]'::jsonb, 0, 'Enjambement: de zin loopt door van de ene versregel naar de volgende zonder punt of komma. Geeft ritme, spanning en benadrukt bepaalde woorden aan het begin van de volgende regel.', NULL, 'sample', NULL, NULL, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is de betekenis van een spreekwoord versus een gezegde?', '["Een spreekwoord is een volkse wijsheid in een vaste uitdrukking; een gezegde is een vaste zinswending die figuurlijk gebruikt wordt","Een gezegde heeft altijd een rijm; een spreekwoord nooit","Een spreekwoord is een volkse wijsheid in een vaste uitdrukking; een onderwerp is een vaste zinswending die figuurlijk gebruikt wordt","Spreekwoord heeft een moraal; gezegde is een persoonlijke mening"]'::jsonb, 0, 'Spreekwoord: volkswijsheid met les (bv. ''Oost west, thuis best''). Gezegde: vaste uitdrukking die figuurlijk iets betekent (bv. ''de pijp aan Maarten geven'' = sterven). Gezegde heeft geen moraal.', NULL, 'sample', 'zinsontleding', 4, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een inversie in zinsbouw?', '["Het omdraaien van de normale volgorde waarbij de persoonsvorm achter het onderwerp staat","Een zin die begint met een bijzin","Het omdraaien van de normale volgorde waarbij de persoonsvorm voor het onderwerp staat","Het herhalen van een woord voor nadruk"]'::jsonb, 2, 'Inversie: ''Gisteren ging ik naar school.'' (PV gaat voor onderwerp ''ik''). Normale volgorde: ''Ik ging gisteren naar school.'' Inversie treedt op als een ander zinsdeel op de eerste positie staat.', NULL, 'sample', 'zinsontleding', 0, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is beeldspraak in het algemeen?', '["Wetenschappelijk taalgebruik met precieze definities of Cijfermatige vergelijkingen in teksten","Wetenschappelijk taalgebruik met precieze definities","Het gebruik van een woord of uitdrukking in een andere dan de letterlijke betekenis","Cijfermatige vergelijkingen in teksten"]'::jsonb, 2, 'Beeldspraak: alle figuurlijke taalvormen waarbij een woord buiten zijn letterlijke betekenis wordt gebruikt — metafoor, vergelijking, personificatie, metonymia.', NULL, 'sample', 'werkwoordsvervoeging', 0, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is het verschil tussen een feit en een mening?', '["Feiten zijn altijd kwantitatief; meningen altijd kwalitatief","Feiten zijn altijd kwantitatief; meningen altijd kwalitatief of Er is geen relevant verschil in betogen of argumentaties","Feiten zijn altijd correct; meningen zijn altijd onjuist","Een feit is controleerbaar/verifieerbaar; een mening is een subjectieve opvatting of oordeel"]'::jsonb, 3, 'Feit: ''Nederland heeft 17 miljoen inwoners'' (verifieerbaar). Mening: ''Nederland is te druk'' (subjectief oordeel). In betogen onderscheiden we wat beweerbaar is van wat mening is.', NULL, 'sample', 'tekstanalyse', 9, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is een tautologie?', '["Het herhalen van dezelfde gedachte in andere woorden zonder nieuwe informatie toe te voegen","Een vergelijking van twee tegengestelde begrippen","Een overdreven uitdrukking voor effect","Een vergelijking van twee tegengestelde begrippen of Een overdreven uitdrukking voor effect"]'::jsonb, 0, 'Tautologie: bv. ''ongehuwde vrijgezel'' of ''wit sneeuw''. De tweede term herhaalt informatie die al in de eerste zit. Soms als stijlfiguur, maar vaak een taalkundige fout.', NULL, 'sample', 'literatuurgeschiedenis', 12, FALSE, NULL),
('nederlands', 'klas1', NULL, 'Wat is het verschil tussen directe en indirecte rede?', '["indirecte rede geeft de inhoud weer zonder aanhalingstekens en past werkwoordstijd aan; Directe rede citeert letterlijk met aanhalingstekens","Directe rede is altijd korter; indirecte rede uitgebreider","Directe rede citeert letterlijk met aanhalingstekens; indirecte rede geeft de inhoud weer zonder aanhalingstekens en past werkwoordstijd aan","Indirecte rede gebruikt meer bijzinnen dan directe rede"]'::jsonb, 2, 'Directe rede: ''Hij zei: "Ik ben moe."'' Indirecte rede: ''Hij zei dat hij moe was.'' Tijdsverandering: ''ben'' wordt ''was''; persoon verandert (ik → hij).', NULL, 'sample', 'werkwoordsvervoeging', 2, FALSE, NULL),
('nederlands', 'klas3', NULL, 'Wat is een trope?', '["Een grammaticaal begrip","Een grammaticaal begrip waarbij woorden in overdrachtelijke betekenis worden gebruikt","Een zinsstructuur","Een stijlfiguur waarbij woorden in overdrachtelijke betekenis worden gebruikt"]'::jsonb, 3, 'Tropen: metafoor, metonymia, synecdoche, ironie — woorden met figuurlijke betekenis.', NULL, 'sample', 'literatuurgeschiedenis', 12, FALSE, NULL),
