('spelling werkwoorden', NULL, 'spelling werkwoorden', 'Welke spelling is correct?', '["Hij rent snel.","Hij rendt snel.","Hij rend snel.","Hij rennd snel."]'::jsonb, 0, 'Stam van ''rennen'' is ''ren''. Bij hij/zij/het: ren + t = rent.', NULL, 'topic', 'spelling', 12, FALSE, NULL),
('spelling werkwoorden', NULL, 'spelling werkwoorden', 'Welke zin is correct?', '["Ze springd over het muurtje.","Ze springdt over het muurtje.","Ze springt over het muurtje.","Ze spring over het muurtje."]'::jsonb, 2, 'Stam van ''springen'' is ''spring''. Bij zij: spring + t = springt.', NULL, 'topic', 'werkwoordsvervoeging', 8, FALSE, NULL),
('spelling werkwoorden', NULL, 'spelling werkwoorden', 'Welke zin is correct?', '["Hij werkd hard.","Hij werkt hard.","Hij werkdt hard.","Hij werkkt hard."]'::jsonb, 1, 'Stam van ''werken'' is ''werk'' (k zit in ''t kofschip). Bij hij: werk + t = werkt.', NULL, 'topic', 'werkwoordsvervoeging', 8, FALSE, NULL),
('spelling werkwoorden', NULL, 'spelling werkwoorden', 'Welke spelling is correct?', '["Ze speeld piano.","Ze speldt piano.","Ze speelt piano.","Ze speeelt piano."]'::jsonb, 2, 'Stam van ''spelen'' is ''speel''. Bij zij: speel + t = speelt.', NULL, 'topic', 'spelling', 12, FALSE, NULL),
('spelling werkwoorden', NULL, 'spelling werkwoorden', 'Welke zin is correct?', '["De hond blafdt.","De hond blafd.","De hond blaaft.","De hond blaft."]'::jsonb, 3, 'Stam van ''blaffen'' is ''blaf''. Bij hij/het: blaf + t = blaft.', NULL, 'topic', 'werkwoordsvervoeging', 8, FALSE, NULL),
('spelling werkwoorden', NULL, 'spelling werkwoorden', 'Welke spelling is correct?', '["Hij kooktd lekker.","Hij kookdt lekker.","Hij kookt lekker.","Hij kookte lekker."]'::jsonb, 2, 'Tegenwoordige tijd: stam ''kook'' + t = kookt. ''Kookte'' is verleden tijd.', NULL, 'topic', 'spelling', 12, FALSE, NULL),
