('cito begrijpend-lezen', NULL, 'cito begrijpend-lezen', 'Een winkel koopt een artikel voor €40 en verkoopt het voor €50. Hoeveel procent winst is dat?', '["10%","20%","25%","30%"]'::jsonb, 2, 'Winst = 10. 10 ÷ 40 × 100 = 25% winst.', NULL, 'topic', 'procenten', 10, FALSE, NULL),
('cito begrijpend-lezen', NULL, 'cito begrijpend-lezen', 'Punt A ligt op coördinaat (2, 3) en punt B op (6, 3). Hoe lang is lijnstuk AB?', '["3","4","5","6"]'::jsonb, 1, 'Zelfde y-waarde, dus horizontale lijn: 6 − 2 = 4 eenheden.', NULL, 'topic', 'negatieve-getallen', 1, FALSE, NULL),
('cito begrijpend-lezen', NULL, 'cito begrijpend-lezen', 'Welk woord is correct gespeld?', '["hobbey","hobby","hobi","hobbe"]'::jsonb, 1, '''Hobby'' — leenwoord uit het Engels, schrijf je precies zo.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito begrijpend-lezen', NULL, 'cito begrijpend-lezen', 'Welke zin heeft een dt-fout?', '["Hij zit op de bank.","Ze fietst naar school.","Hij vind het leuk.","Zij zingt mooi."]'::jsonb, 2, '''Vind'' is fout — moet ''vindt'' zijn (hij/zij/het + stam ''vind'' + t).', NULL, 'topic', 'werkwoordsvervoeging', 11, FALSE, NULL),
('cito begrijpend-lezen', NULL, 'cito begrijpend-lezen', 'Welk woord heeft een dubbele medeklinker als meervoud?', '["bal → balen","bal → ballen","bal → balls","bal → bals"]'::jsonb, 1, '''Ballen'' heeft een dubbele l omdat de klinker a kort is in ''bal'' (bal → ballen).', NULL, 'topic', NULL, NULL, FALSE, NULL),
('cito begrijpend-lezen', NULL, 'cito begrijpend-lezen', 'Lees de tekst:
INSERT INTO public.questions (subject, level, topic_key, q, options, answer, explanation, svg, source, path_id, step_idx, image_in_explanation, question_source) VALUES
('cito gemengd', NULL, 'cito gemengd', 'Welke spelling is correct?', '["aanbeveling","aanbeveeling","aanbevelling","aanbeveelling"]'::jsonb, 0, '''Aanbeveling'' = aan + beveling. Geen verdubbeling nodig — de e is lang (open lettergreep).', NULL, 'topic', 'spelling', 12, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Welke spelling is correct?', '["kunnen","kunen","kunnnen","kunenn"]'::jsonb, 0, '''Kunnen'' heeft een dubbele n omdat de u kort is (gesloten lettergreep: kun-nen).', NULL, 'topic', 'spelling', 12, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Welk woord is correct gespeld?', '["tennis","tenis","teniss","ténnis"]'::jsonb, 0, '''Tennis'' heeft dubbel n en dubbel s — een leenwoord uit het Engels dat zo is overgenomen.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Welke spelling is correct?', '["verantwoordelijkheid","verantwoordelikheid","verantwoordelijcheid","verantwoorderlijkheid"]'::jsonb, 0, '''Verantwoordelijkheid'' — let op de -lijk uitgang en de -heid suffix.', NULL, 'topic', 'spelling', 12, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Welk woord is fout gespeld?', '["bibliotheek","chocolade","paraplu","reciet"]'::jsonb, 3, '''Reciet'' is fout — het juiste woord is ''recept'' (van het Frans/Latijn).', NULL, 'topic', 'krachten-natuurkunde', 6, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Welke spelling is correct?', '["nauwkeurig","nauwkeurich","naukeurig","nauwkeurieg"]'::jsonb, 0, '''Nauwkeurig'' — nauw + keurig. Schrijf ''nauw'' met een w.', NULL, 'topic', 'spelling', 12, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Welk woord is correct?', '["waarschijnlijk","waarsijnlijk","waarscijnlijk","waarsschijnlijk"]'::jsonb, 0, '''Waarschijnlijk'' — let op de ''sch'' combinatie en de -lijk uitgang.', NULL, 'topic', 'krachten-natuurkunde', 1, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is een synoniem voor ''beseffen''?', '["vergeten","dromen","doordringen","negeren"]'::jsonb, 2, '''Doordringen'' en ''beseffen'' betekenen hetzelfde — iets dringt tot je door.', NULL, 'topic', 'krachten-natuurkunde', 1, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat betekent ''met de mond vol tanden staan''?', '["je tanden laten zien","niets kunnen zeggen van verbazing","hard schreeuwen","lachen om een grap"]'::jsonb, 1, 'Met de mond vol tanden staan betekent dat je zo verbaasd bent dat je niets kunt zeggen.', NULL, 'topic', 'goniometrie', 1, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is een synoniem voor ''aarzelend''?', '["vastberaden","snel","besluiteloos","zeker"]'::jsonb, 2, '''Aarzelend'' en ''besluiteloos'' beschrijven allebei iemand die twijfelt.', NULL, 'topic', 'schrijfvaardigheid', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat betekent ''nauwkeurig''?', '["snel en vluchtig","zorgvuldig en precies","rommelig","luid"]'::jsonb, 1, '''Nauwkeurig'' betekent dat je heel precies en zorgvuldig te werk gaat.', NULL, 'topic', 'krachten-natuurkunde', 7, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is het tegenovergestelde van ''vrijwillig''?', '["blij","gratis","verplicht","samen"]'::jsonb, 2, 'Het tegenovergestelde van ''vrijwillig'' is ''verplicht''.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat betekent ''een blauwtje lopen''?', '["blauw verven","afgewezen worden","een prijs winnen","verdwalen"]'::jsonb, 1, 'Een blauwtje lopen betekent dat je afgewezen wordt.', NULL, 'topic', 'werkwoordsvervoeging', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is een synoniem voor ''geloofwaardig''?', '["onbetrouwbaar","overtuigend","vaag","vervelend"]'::jsonb, 1, '''Geloofwaardig'' en ''overtuigend'' betekenen dat iets te vertrouwen is.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat betekent ''ambitieus''?', '["lui en onverschillig","verlegen en stil","gedreven en doelgericht","aardig en vriendelijk"]'::jsonb, 2, '''Ambitieus'' betekent dat je hoge doelen stelt en er hard voor werkt.', NULL, 'topic', 'krachten-natuurkunde', 7, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is het tegenovergestelde van ''optimistisch''?', '["vrolijk","actief","pessimistisch","realistisch"]'::jsonb, 2, 'Het tegenovergestelde van ''optimistisch'' is ''pessimistisch''.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat betekent ''iets door de vingers zien''?', '["iets goed bekijken","een fout negeren en vergeven","iets stelen","heel snel lezen"]'::jsonb, 1, 'Iets door de vingers zien betekent dat je een fout negeert en niet straft.', NULL, 'topic', 'krachten-natuurkunde', 4, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is een synoniem voor ''analyseren''?', '["verzamelen","uitleggen","onderzoeken","verwijderen"]'::jsonb, 2, '''Analyseren'' en ''onderzoeken'' betekenen allebei iets zorgvuldig bestuderen.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat betekent ''genuanceerd''?', '["simpel en duidelijk","met aandacht voor kleine verschillen","luid en duidelijk","snel en efficiënt"]'::jsonb, 1, '''Genuanceerd'' betekent dat je rekening houdt met kleine verschillen en niet alles zwart-wit ziet.', NULL, 'topic', 'atoombouw-scheikunde', 9, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is het tegenovergestelde van ''abstract''?', '["ingewikkeld","concreet","vaag","theoretisch"]'::jsonb, 1, 'Het tegenovergestelde van ''abstract'' is ''concreet'' (tastbaar en duidelijk).', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat betekent ''prominent''?', '["onbekend en verborgen","opvallend en belangrijk","klein en onbeduidend","oud en versleten"]'::jsonb, 1, '''Prominent'' betekent dat iemand of iets duidelijk zichtbaar en belangrijk is.', NULL, 'topic', 'krachten-natuurkunde', 7, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is een synoniem voor ''tolerant''?', '["streng","verdraagzaam","kritisch","onverschillig"]'::jsonb, 1, '''Tolerant'' en ''verdraagzaam'' betekenen allebei dat je anderen accepteert zoals ze zijn.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is een synoniem voor ''onvermijdelijk''?', '["toevallig","onontkoombaar","onwaarschijnlijk","tijdelijk"]'::jsonb, 1, '''Onvermijdelijk'' en ''onontkoombaar'' betekenen allebei dat je er niet aan kunt ontkomen.', NULL, 'topic', NULL, NULL, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat betekent ''diplomatiek''?', '["altijd direct en eerlijk","tactisch en zonder anderen te kwetsen","stiekem en onbetrouwbaar","luid en overtuigend"]'::jsonb, 1, '''Diplomatiek'' betekent dat je dingen op een tactvolle manier zegt zonder mensen te kwetsen.', NULL, 'topic', 'krachten-natuurkunde', 7, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is het tegenovergestelde van ''chronologisch''?', '["alfabetisch","logisch","willekeurig","systematisch"]'::jsonb, 2, 'Het tegenovergestelde van ''chronologisch'' (op volgorde van tijd) is ''willekeurig''.', NULL, 'topic', 'logaritmen', 10, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat betekent ''empathie''?', '["jezelf altijd vooropstellen","het gevoel van een ander begrijpen","goed kunnen discussiëren","een hekel hebben aan anderen"]'::jsonb, 1, '''Empathie'' is het vermogen om je in te leven in de gevoelens van een ander.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is een synoniem voor ''overbodig''?', '["noodzakelijk","handig","nutteloos","dringend"]'::jsonb, 2, '''Overbodig'' en ''nutteloos'' betekenen allebei dat iets niet nodig is.', NULL, 'topic', 'krachten-natuurkunde', 4, FALSE, NULL),
