('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was de Slag om de Atlantische Oceaan?', '["Strijd om bevoorradingsroutes WO2","Een piratenoorlog","Een piratenoorlog of Een handelsoorlog","Een handelsoorlog"]'::jsonb, 0, 'Duitsland probeerde Britse bevoorradingslijnen af te snijden.', NULL, 'topic', 'krachten-natuurkunde', 8, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was Apartheid?', '["Officieel rassenscheidingsstelsel in Zuid-Afrika","Een Indiaas kastenstelsel","Een Australisch systeem","Officieel rassenscheidingsstelsel in noord-Afrika"]'::jsonb, 0, 'Apartheid in Zuid-Afrika: 1948-1994.', NULL, 'topic', NULL, NULL, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wanneer werd de VN opgericht?', '["1950","1945","1918","1939"]'::jsonb, 1, 'De Verenigde Naties: 1945, na WO2.', NULL, 'topic', 'nederlandse-staat-maatschappijleer', 9, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was de Perestrojka?', '["Russische militaire doctrine of Een Russische revolutie","Russische militaire doctrine","Een Russische revolutie","Gorbatsjovs hervormingsprogramma"]'::jsonb, 3, 'Perestrojka (1986): economische hervorming onder Gorbatsjov.', NULL, 'topic', 'krachten-natuurkunde', 4, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wanneer viel de Berlijnse Muur?', '["1991","1989","1985","1987"]'::jsonb, 1, '9 november 1989.', NULL, 'topic', 'tijdvakken-geschiedenis', 10, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was de Eerste Wereldoorlog?', '["1920-1930","1939-1945","1900-1910","1914-1918"]'::jsonb, 3, 'WO1: 1914-1918, ook wel ''de Grote Oorlog''.', NULL, 'topic', 'tijdvakken-geschiedenis', 9, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Welk verdrag beëindigde WO1?', '["Verdrag van Utrecht","Verdrag van Utrecht of Verdrag van Parijs","Verdrag van Versailles","Verdrag van Parijs"]'::jsonb, 2, 'Het Verdrag van Versailles (1919).', NULL, 'topic', 'tijdvakken-geschiedenis', 9, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was de Olympische Spelen van 1936?', '["Eerste moderne spelen","Eerste moderne spelen of Geannuleerde spelen","Eerste Winterspelen","Hitlers propagandaspelen in Berlijn"]'::jsonb, 3, 'Berlijn 1936: door Hitler gebruikt als propaganda.', NULL, 'topic', 'krachten-natuurkunde', 4, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wie was Mahatma Gandhi?', '["Pakistans eerste president of Indiaas militair leider","Pakistans eerste president","Indiaas militair leider","Leider van geweldloze onafhankelijkheidsstrijd India"]'::jsonb, 3, 'Gandhi leidde de geweldloze strijd voor Indiase onafhankelijkheid.', NULL, 'topic', 'kansrekening', 0, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was de Cubacrisis?', '["Nucleaire dreiging VS-Sovjet-Unie in 1962","Handelsembargo op Cuba of Cubaanse revolutie","Inval in Cuba 1961","Handelsembargo op Cuba"]'::jsonb, 0, '1962: Sovjet-Unie plaatste kernraketten op Cuba.', NULL, 'topic', 'cel-biologie', 0, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wanneer werd de EU opgericht?', '["2000","1992","1945","1957"]'::jsonb, 3, 'Verdrag van Rome (1957) stichtte de EEG, voorloper van de EU.', NULL, 'topic', 'tijdvakken-geschiedenis', 2, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was de impact van de Industriële Revolutie op de samenleving?', '["Verstedelijking, fabrieksarbeid en sociale ongelijkheid groeiden","Minder productie in het dagelijks taalgebruik en literatuur","Meer feodalisme","Meer boerderijen"]'::jsonb, 0, 'Industrialisatie: trek naar steden, fabriekssysteem, nieuwe arbeidersklasse.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was de Reformatie?', '["Religieuze vernieuwingsbeweging die leidde tot het protestantisme (Luther 1517)","Een politieke revolutie, Een economische hervorming en Een artistieke beweging die leidde tot het protestantisme (Luther 1517)","Een economische hervorming","Een artistieke beweging"]'::jsonb, 0, 'Luther, Calvijn en Zwingli hervormden het christendom. Scheuring van de kerk.', NULL, 'topic', 'tijdvakken-geschiedenis', 5, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was de Tachtigjarige Oorlog?', '["Nederlandse Opstand tegen Spanje (1568-1648)","Een burgeroorlog in Engeland","Een Napoleon-oorlog","Een burgeroorlog in Engeland of Een Napoleon-oorlog"]'::jsonb, 0, 'De Tachtigjarige Oorlog leidde tot de onafhankelijkheid van de Republiek der Zeven Provinciën.', NULL, 'topic', 'logaritmen', 0, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was het Akkoord van München (1938)?', '["Britisch-Frans toegeven aan Hitlers eisen over Tsjecho-Slowakije","NATO-oprichting","NATO-oprichting, Vrede na WO1 en Handelsovereenkomst over Tsjecho-Slowakije","Handelsovereenkomst"]'::jsonb, 0, 'München 1938: Chamberlain gaf Sudetenland aan Hitler — klassiek voorbeeld van appeasement.', NULL, 'topic', 'krachten-natuurkunde', 2, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was de rol van de SS in Nazi-Duitsland?', '["Elite-paramilitaire organisatie die concentratiekampen beheerde en terreur uitvoerde","Een militaire eenheid voor verdediging","Een economische organisatie","Een militaire eenheid voor verdediging die concentratiekampen beheerde en terreur uitvoerde"]'::jsonb, 0, 'De SS (Schutzstaffel) was verantwoordelijk voor de uitvoering van de Holocaust.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wie was Winston Churchill?', '["Britse premier die leiding gaf aan de strijd tegen Hitler","VS-president tijdens WO2 die leiding gaf aan de strijd tegen Hitler","Russische leider","VS-president tijdens WO2"]'::jsonb, 0, 'Churchill (1874-1965): Britse premier, symbool van Brits verzet tegen Hitler.', NULL, 'topic', 'krachten-natuurkunde', 9, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was het IJzeren Gordijn?', '["Een verdedigingslinie in WO1","Denkbeeldige grens die oost-Europa van de communistische Oostblok scheidde","Een muur in Berlijn","Denkbeeldige grens die West-Europa van de communistische Oostblok scheidde"]'::jsonb, 3, 'Het IJzeren Gordijn (Churchill, 1946) symboliseerde de politieke scheiding van Europa.', NULL, 'topic', 'nederlandse-staat-maatschappijleer', 0, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat betekende dekolonisatie voor Afrika?', '["Afrikaanse landen werden onafhankelijk na WO2","Meer Europese controle","Economische integratie met Europa of Meer Europese controle","Economische integratie met Europa"]'::jsonb, 0, 'Na 1945 werd Afrika grotendeels onafhankelijk: Ghana (1957), Nigeria (1960), enz.', NULL, 'topic', 'kansrekening', 7, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was de Veluwse Oproer of Patriottenbeweging in Nederland?', '["Een boerenopstand, Een handelsdispuut en Een religieuze beweging die het gezag van de stadhouder betwistte","Een handelsdispuut","Een religieuze beweging","Een 18e-eeuwse democratische beweging die het gezag van de stadhouder betwistte"]'::jsonb, 3, 'De Patriotten (jaren 1780) streefden naar meer volkssoevereiniteit en minder Oranje-macht.', NULL, 'topic', 'machten', 1, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wat was het Weimar-probleem?', '["De zwakheid van de Weimarrepubliek die de opkomst van Hitler mogelijk maakte","Een economisch systeem","Een stad in Duitsland","Een economisch systeem van de Weimarrepubliek die de opkomst van Hitler mogelijk maakte"]'::jsonb, 0, 'Hyperinflatie, reparaties en politieke instabiliteit ondermijnden de Weimarrepubliek.', NULL, 'topic', NULL, NULL, FALSE, NULL),
('cito groep8-wereldorientatie', NULL, 'cito groep8-wereldorientatie', 'Wanneer werd Nederland bevrijd in WO2?', '["1945 (volledig)","1944 (volledig)","1943","1944 (deels)"]'::jsonb, 0, 'Het zuiden werd in 1944 bevrijd; de rest volgde op 5 mei 1945.', NULL, 'topic', 'tijdvakken-geschiedenis', 6, FALSE, NULL),
