('cito studievaardigheden', NULL, 'cito studievaardigheden', 'Bekijk de stadskaart. Hoeveel metrostops zijn er van Station Noord naar het Ziekenhuis?', '["1 stop","2 stops","3 stops","4 stops"]'::jsonb, 2, 'Van Station Noord → Centrum → Station Zuid → Ziekenhuis: dat zijn 3 stops.', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 280 90"><rect width="280" height="90" rx="8" fill="#0d1f3c"/><text x="140" y="14" font-size="10" font-weight="bold" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">🚇 Metrokaart</text><line x1="20" y1="50" x2="260" y2="50" stroke="#64b5f6" stroke-width="3"/><circle cx="20" cy="50" r="7" fill="#1e88e5" stroke="#fff" stroke-width="1.5"/><text x="20" y="40" font-size="7.5" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">Stn. Noord</text><text x="20" y="70" font-size="7" fill="#aaa" text-anchor="middle" font-family="sans-serif">▶ start</text><circle cx="100" cy="50" r="6" fill="#162033" stroke="#64b5f6" stroke-width="2"/><text x="100" y="40" font-size="7.5" fill="#aaa" text-anchor="middle" font-family="sans-serif">Centrum</text><text x="100" y="70" font-size="7" fill="#aaa" text-anchor="middle" font-family="sans-serif">stop 1</text><circle cx="180" cy="50" r="6" fill="#162033" stroke="#64b5f6" stroke-width="2"/><text x="180" y="40" font-size="7.5" fill="#aaa" text-anchor="middle" font-family="sans-serif">Stn. Zuid</text><text x="180" y="70" font-size="7" fill="#aaa" text-anchor="middle" font-family="sans-serif">stop 2</text><circle cx="260" cy="50" r="7" fill="#f48fb1" stroke="#fff" stroke-width="1.5"/><text x="260" y="40" font-size="7.5" fill="#f48fb1" font-weight="bold" text-anchor="middle" font-family="sans-serif">Ziekenhuis</text><text x="260" y="70" font-size="7" fill="#ccc" text-anchor="middle" font-family="sans-serif">stop 3 </text></svg>', 'topic', 'kansrekening', 3, FALSE, NULL),
('cito studievaardigheden', NULL, 'cito studievaardigheden', 'Bekijk de kaart met kompasroos. In welke richting van stad A ligt stad B?', '["Noord","Oost","Zuid","West"]'::jsonb, 2, 'Stad B ligt onder stad A op de kaart. Op een kaart is onder = Zuid.', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 240 120"><rect width="240" height="120" rx="8" fill="#0d1f3c"/><text x="120" y="14" font-size="10" font-weight="bold" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">🧭 Kaart met kompasroos</text><rect x="10" y="22" width="140" height="90" rx="6" fill="#162033" stroke="#334" stroke-width="1"/><circle cx="50" cy="55" r="10" fill="#1e88e5" opacity="0.8"/><text x="50" y="59" font-size="9" fill="#fff" text-anchor="middle" font-family="sans-serif">A</text><circle cx="80" cy="90" r="10" fill="#f59e0b" opacity="0.8"/><text x="80" y="94" font-size="9" fill="#fff" text-anchor="middle" font-family="sans-serif">B</text><line x1="50" y1="65" x2="80" y2="80" stroke="#ffd700" stroke-width="1.5" stroke-dasharray="3,2"/><text x="170" y="35" font-size="10" fill="#fff" text-anchor="middle" font-weight="bold" font-family="sans-serif">N</text><text x="170" y="100" font-size="10" fill="#fff" text-anchor="middle" font-weight="bold" font-family="sans-serif">Z</text><text x="200" y="68" font-size="10" fill="#fff" text-anchor="middle" font-weight="bold" font-family="sans-serif">O</text><text x="140" y="68" font-size="10" fill="#fff" text-anchor="middle" font-weight="bold" font-family="sans-serif">W</text><line x1="170" y1="40" x2="170" y2="95" stroke="#aaa" stroke-width="1"/><line x1="145" y1="67" x2="195" y2="67" stroke="#aaa" stroke-width="1"/><polygon points="170,38 166,50 174,50" fill="#f48fb1"/><text x="170" y="110" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">B ligt ten Zuiden van A </text></svg>', 'topic', 'kansrekening', 5, FALSE, NULL),
('cito studievaardigheden', NULL, 'cito studievaardigheden', 'Bekijk de hoogtekaart. Welk punt ligt het hoogst?', '["Punt A (200m)","Punt B (150m)","Punt C (350m)","Punt D (280m)"]'::jsonb, 2, 'Punt C staat op 350m — dat is de hoogste waarde op de kaart.', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 260 115"><rect width="260" height="115" rx="8" fill="#0d1f3c"/><text x="130" y="14" font-size="10" font-weight="bold" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">🏔 Hoogtekaart (meter)</text><polygon points="30,95 80,40 130,70 180,25 230,60 260,95" fill="none" stroke="#334" stroke-width="1"/><polygon points="30,95 80,50 130,80 180,35 230,70 260,95" fill="rgba(43,189,126,0.08)" stroke="rgba(43,189,126,0.3)" stroke-width="1"/><polygon points="30,95 80,60 130,85 180,45 230,80 260,95" fill="rgba(43,189,126,0.05)" stroke="rgba(43,189,126,0.15)" stroke-width="1"/><circle cx="80" cy="50" r="6" fill="#64b5f6"/><text x="80" y="42" font-size="8" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">A 200m</text><circle cx="130" cy="70" r="6" fill="#f59e0b"/><text x="130" y="62" font-size="8" fill="#f59e0b" text-anchor="middle" font-family="sans-serif">B 150m</text><circle cx="180" cy="28" r="5" fill="#f48fb1"/><text x="180" y="20" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">C 350m </text><circle cx="230" cy="60" r="6" fill="#f48fb1"/><text x="230" y="52" font-size="8" fill="#f48fb1" text-anchor="middle" font-family="sans-serif">D 280m</text></svg>', 'topic', 'kansrekening', 5, FALSE, NULL),
('cito studievaardigheden', NULL, 'cito studievaardigheden', 'Bekijk het rooster. Welk vak heeft Anna op woensdag in het 3e uur?', '["Rekenen","Taal","Gym","Aardrijkskunde"]'::jsonb, 2, 'Op woensdag, 3e uur staat Gym in het rooster.', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 280 115"><rect width="280" height="115" rx="8" fill="#0d1f3c"/><text x="140" y="14" font-size="10" font-weight="bold" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">📋 Rooster Anna</text><rect x="8" y="20" width="264" height="16" rx="2" fill="#1a3a5c"/><text x="40" y="31" font-size="8.5" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">Ma</text><text x="96" y="31" font-size="8.5" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">Di</text><text x="152" y="31" font-size="8.5" fill="#ccc" text-anchor="middle" font-family="sans-serif">Wo</text><text x="208" y="31" font-size="8.5" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">Do</text><text x="264" y="31" font-size="8.5" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">Vr</text><text x="12" y="47" font-size="8" fill="#aaa" font-family="sans-serif">1e</text><text x="40" y="47" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Rekenen</text><text x="96" y="47" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Taal</text><text x="152" y="47" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Rekenen</text><text x="208" y="47" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Gym</text><text x="264" y="47" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Taal</text><line x1="8" y1="52" x2="272" y2="52" stroke="#223" stroke-width="1"/><text x="12" y="66" font-size="8" fill="#aaa" font-family="sans-serif">2e</text><text x="40" y="66" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Taal</text><text x="96" y="66" font-size="8" fill="#ccc" text-anchor="