('cito groep8-studievaardigheden', NULL, 'cito groep8-studievaardigheden', 'Bekijk de hoogtekaart. Welk punt ligt het hoogst?', '["Punt A (200m)","Punt B (150m)","Punt C (350m)","Punt D (280m)"]'::jsonb, 2, 'Punt C staat op 350m — dat is de hoogste waarde op de kaart.', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 260 115"><rect width="260" height="115" rx="8" fill="#0d1f3c"/><text x="130" y="14" font-size="10" font-weight="bold" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">🏔 Hoogtekaart (meter)</text><polygon points="30,95 80,40 130,70 180,25 230,60 260,95" fill="none" stroke="#334" stroke-width="1"/><polygon points="30,95 80,50 130,80 180,35 230,70 260,95" fill="rgba(43,189,126,0.08)" stroke="rgba(43,189,126,0.3)" stroke-width="1"/><polygon points="30,95 80,60 130,85 180,45 230,80 260,95" fill="rgba(43,189,126,0.05)" stroke="rgba(43,189,126,0.15)" stroke-width="1"/><circle cx="80" cy="50" r="6" fill="#64b5f6"/><text x="80" y="42" font-size="8" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">A 200m</text><circle cx="130" cy="70" r="6" fill="#f59e0b"/><text x="130" y="62" font-size="8" fill="#f59e0b" text-anchor="middle" font-family="sans-serif">B 150m</text><circle cx="180" cy="28" r="5" fill="#f48fb1"/><text x="180" y="20" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">C 350m </text><circle cx="230" cy="60" r="6" fill="#f48fb1"/><text x="230" y="52" font-size="8" fill="#f48fb1" text-anchor="middle" font-family="sans-serif">D 280m</text></svg>', 'topic', 'kansrekening', 5, FALSE, NULL),
('cito groep8-studievaardigheden', NULL, 'cito groep8-studievaardigheden', 'Bekijk het rooster. Welk vak heeft Anna op woensdag in het 3e uur?', '["Rekenen","Taal","Gym","Aardrijkskunde"]'::jsonb, 2, 'Op woensdag, 3e uur staat Gym in het rooster.', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 280 115"><rect width="280" height="115" rx="8" fill="#0d1f3c"/><text x="140" y="14" font-size="10" font-weight="bold" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">📋 Rooster Anna</text><rect x="8" y="20" width="264" height="16" rx="2" fill="#1a3a5c"/><text x="40" y="31" font-size="8.5" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">Ma</text><text x="96" y="31" font-size="8.5" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">Di</text><text x="152" y="31" font-size="8.5" fill="#ccc" text-anchor="middle" font-family="sans-serif">Wo</text><text x="208" y="31" font-size="8.5" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">Do</text><text x="264" y="31" font-size="8.5" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">Vr</text><text x="12" y="47" font-size="8" fill="#aaa" font-family="sans-serif">1e</text><text x="40" y="47" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Rekenen</text><text x="96" y="47" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Taal</text><text x="152" y="47" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Rekenen</text><text x="208" y="47" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Gym</text><text x="264" y="47" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Taal</text><line x1="8" y1="52" x2="272" y2="52" stroke="#223" stroke-width="1"/><text x="12" y="66" font-size="8" fill="#aaa" font-family="sans-serif">2e</text><text x="40" y="66" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">Taal</text><text x="96" y="66" font-size="8" fill="#ccc"