('cito groep8-studievaardigheden', NULL, 'cito groep8-studievaardigheden', 'Bekijk het Venn-diagram. Hoeveel leerlingen spelen zowel piano als gitaar?', '["3 leerlingen","5 leerlingen","8 leerlingen","11 leerlingen"]'::jsonb, 0, 'Het overlappende middenstuk van het Venn-diagram toont 3 leerlingen die beide instrumenten spelen.', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 260 120"><rect width="260" height="120" rx="8" fill="#0d1f3c"/><text x="130" y="14" font-size="10" font-weight="bold" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">🎵 Venn-diagram muziek</text><circle cx="95" cy="68" r="42" fill="#1e88e5" opacity="0.25" stroke="#1e88e5" stroke-width="2"/><circle cx="165" cy="68" r="42" fill="#f48fb1" opacity="0.15" stroke="#f48fb1" stroke-width="2"/><text x="72" y="65" font-size="22" text-anchor="middle" font-family="sans-serif">5</text><text x="72" y="80" font-size="8" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">alleen piano</text><text x="130" y="65" font-size="22" fill="#ffd700" font-weight="bold" text-anchor="middle" font-family="sans-serif">3</text><text x="130" y="80" font-size="7.5" fill="#ccc" text-anchor="middle" font-family="sans-serif">beiden </text><text x="188" y="65" font-size="22" text-anchor="middle" font-family="sans-serif">2</text><text x="188" y="80" font-size="8" fill="#ccc" text-anchor="middle" font-family="sans-serif">alleen gitaar</text><text x="80" y="112" font-size="8.5" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">Piano</text><text x="180" y="112" font-size="8.5" fill="#ccc" text-anchor="middle" font-family="sans-serif">Gitaar</text></svg>', 'topic', 'krachten-natuurkunde', 5, FALSE, NULL),
('cito groep8-studievaardigheden', NULL, 'cito groep8-studievaardigheden', 'Bekijk het Venn-diagram. Hoeveel leerlingen doen aan sport of muziek (of beide)?', '["12 leerlingen","15 leerlingen","17 leerlingen","20 leerlingen"]'::jsonb, 2, 'Sport alleen (8) + Muziek alleen (5) + Beiden (4) = 17 leerlingen in totaal.', '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 260 120"><rect width="260" height="120" rx="8" fill="#0d1f3c"/><text x="130" y="14" font-size="10" font-weight="bold" fill="#64b5f6" text-anchor="middle" font-family="sans-serif">🏅 Venn-diagram sport & muziek</text><circle cx="95" cy="68" r="42" fill="#f48fb1" opacity="0.2" stroke="#f48fb1" stroke-width="2"/><circle cx="165" cy="68" r="42" fill="#f59e0b" opacity="0.2" stroke="#f59e0b" stroke-width="2"/><text x="72" y="65" font-size="22" text-anchor="middle" font-family="sans-serif">8</text><text x="72" y="80" font-size="8" fill="#f48fb1" text-anchor="middle" font-family="sans-serif">alleen sport</text><text x="130" y="65" font-size="22" fill="#ffd700" font-weight="bold" text-anchor="middle" font-family="sans-serif">4</text><text x="130" y="80" font-size="7.5" fill="#ffd700" text-anchor="middle" font-family="sans-serif">beiden</text><text x="188" y="65" font-size="22" text-anchor="middle" font-family="sans-serif">5</text><text x="188" y="80" font-size="8" fill="#f59e0b" text-anchor="middle" font-family="sans-serif">alleen muziek</text><text x="80" y="112" font-size="8.5" fill="#f48fb1" text-anchor="middle" font-family="sans-serif">Sport</text><text x="180" y="112" font-size="8.5" fill="#f59e0b" text-anchor="middle" font-family="sans-serif">Muziek</text><text x="130" y="112" font-size="7.5" fill="#ccc" text-anchor="middle" font-family="sans-serif">8+5+4=17</text></svg>', 'topic', 'krachten-natuurkunde', 5, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Een bakker bakt 180 broodjes. Hij verkoopt ze per 6 in een zak. Hoeveel zakken heeft hij nodig?', '["24","28","30","36"]'::jsonb, 2, '180 ÷ 6 = 30 zakken.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Een fiets kost €240. Er is 15% korting. Wat betaal je?', '["€196","€200","€204","€210"]'::jsonb, 2, '15% van 240 = 36. 240 − 36 = €204.', NULL, 'topic', 'procenten', 8, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Een rechthoek heeft een lengte van 13 cm en een breedte van 8 cm. Wat is de oppervlakte?', '["42 cm²","84 cm²","104 cm²","96 cm²"]'::jsonb, 2, 'Oppervlakte = 13 × 8 = 104 cm².', NULL, 'topic', 'ruimtemeetkunde', 1, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Hoeveel minuten zijn er in 3 uur en 20 minuten?', '["180 min","200 min","210 min","220 min"]'::jsonb, 1, '3 uur = 180 min. 180 + 20 = 200 minuten.', NULL, 'topic', NULL, NULL, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', '0,8 × 0,5 = ?', '["0,04","0,4","4","40"]'::jsonb, 1, '8 × 5 = 40, twee decimalen → 0,40 = 0,4.', NULL, 'topic', NULL, NULL, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Wat is ⅖ van 60?', '["20","24","30","12"]'::jsonb, 1, '⅖ × 60 = 2 × 12 = 24.', NULL, 'topic', NULL, NULL, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', '4 potloden kosten samen €3,20. Wat kost 1 potlood?', '["€0,70","€0,75","€0,80","€0,85"]'::jsonb, 2, '€3,20 ÷ 4 = €0,80 per potlood.', NULL, 'topic', 'balans-beco', 6, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'De omtrek van een vierkant is 52 cm. Wat is de oppervlakte?', '["144 cm²","169 cm²","182 cm²","196 cm²"]'::jsonb, 1, 'Zijde = 52 ÷ 4 = 13 cm. Oppervlakte = 13 × 13 = 169 cm².', NULL, 'topic', 'ruimtemeetkunde', 4, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Een bus rijdt 80 km in 1 uur. Hoeveel km rijdt hij in 45 minuten?', '["50 km","55 km","60 km","65 km"]'::jsonb, 2, '45 min = ¾ uur. 80 × ¾ = 60 km.', NULL, 'topic', 'breuken', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Zet om: 1,25 = ?', '["1¾","1⅓","1¼","1½"]'::jsonb, 2, '0,25 = ¼, dus 1,25 = 1¼.', NULL, 'topic', NULL, NULL, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'De temperaturen deze week waren: 12, 15, 11, 16, 11°C. Wat is de gemiddelde temperatuur?', '["12°C","13°C","14°C","15°C"]'::jsonb, 1, '12 + 15 + 11 + 16 + 11 = 65. 65 ÷ 5 = 13°C.', NULL, 'topic', 'statistiek', 3, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Op een kaart staat schaal 1:50.000. Een afstand van 4 cm op de kaart is in werkelijkheid:', '["2 km","4 km","20 km","200 m"]'::jsonb, 0, '4 cm × 50.000 = 200.000 cm = 2.000 m = 2 km.', NULL, 'topic', 'verhoudingen', 6, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'De getallen 3, 7, 8, 3, 9, 3, 5. Wat is de modus?', '["3","5","7","9"]'::jsonb, 0, 'De modus is het getal dat het vaakst voorkomt: 3 komt drie keer voor.', NULL, 'topic', 'statistiek', 4, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Het was −5°C. Nu is het 8°C warmer. Wat is de temperatuur nu?', '["3°C","4°C","−3°C","13°C"]'::jsonb, 0, '−5 + 8 = 3°C.', NULL, 'topic', 'negatieve-getallen', 8, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Een aquarium is 60 cm lang, 30 cm breed en 40 cm hoog. Hoeveel liter water past erin? (1 liter = 1.000 cm³)', '["42 liter","60 liter","72 liter","80 liter"]'::jsonb, 2, 'Volume = 60 × 30 × 40 = 72.000 cm³ = 72 liter.', NULL, 'topic', 'krachten-natuurkunde', 4, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Welk getal ontbreekt? 2, 5, 11, 23, ...', '["35","41","47","44"]'::jsonb, 2, 'Patroon: ×2 + 1. 2→5, 5→11, 11→23, 23→47.', NULL, 'topic', 'krachten-natuurkunde', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Een trui kost €75. De prijs stijgt met 8%. Wat is de nieuwe prijs?', '["€79","€81","€83","€85"]'::jsonb, 1, '8% van 75 = 6. 75 + 6 = €81.', NULL, 'topic', 'procenten', 10, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Je betaalt met €50 voor iets van €37,40. Hoeveel wisselgeld krijg je?', '["€11,40","€12,60","€13,60","€12,40"]'::jsonb, 1, '50,00 − 37,40 = €12,60.', NULL, 'topic', 'negatieve-getallen', 4, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'In een klas zitten 30 leerlingen. De verhouding jongens:meisjes is 2:3. Hoeveel meisjes zijn er?', '["12","15","18","20"]'::jsonb, 2, '3 van de 5 delen zijn meisjes: ⅗ × 30 = 18.', NULL, 'topic', 'verhoudingen', 0, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Hoeveel centiliter is 2,4 liter?', '["24 cl","240 cl","2.400 cl","0,24 cl"]'::jsonb, 1, '1 liter = 100 cl. 2,4 × 100 = 240 cl.', NULL, 'topic', NULL, NULL, FALSE, NULL),
('cito gemengd', NULL, 'cito gemengd', 'Een winkel koopt een artikel voor €40 en verkoopt het voor €50. Hoeveel procent winst is dat?', '["10%","20%","25%","30%"]'::jsonb, 2, 'Winst = 10. 10 ÷ 40 × 100 = 25% winst.', NULL, 'topic', 'procenten', 10, FALSE, NULL),
