('cito groep8-gemengd', NULL, 'cito groep8-gemengd', 'Welke zin is fout?', '["Ze ziet een vogel.","Hij loopt snel.","De hond blaft.","Wij rent naar huis."]'::jsonb, 3, '''Wij'' gebruikt de basisvorm: ''wij rennen'', niet ''wij rent''. De -t geldt alleen bij hij/zij/het.', NULL, 'topic', 'werkwoordsvervoeging', 2, FALSE, NULL),
('cito groep8-gemengd', NULL, 'cito groep8-gemengd', 'Welke spelling is correct?', '["Hij heeft gewerkt.","Hij heeft gewerkte.","Hij heeft gewerktd.","Hij heeft geworkt."]'::jsonb, 0, 'Voltooid deelwoord van ''werken'' (t kofschip): ge + stam + t = gewerkt.', NULL, 'topic', 'spelling', 12, FALSE, NULL),
